function makeCounter() {
  let count = 0; // this variable lives inside makeCounter

  function increment() {
    count++;          // increment() 'closes over' count
    console.log(count);
  }

  return increment; // return the inner function
}

const counter = makeCounter();
// makeCounter() has finished, but count is NOT garbage collected
// because counter (the inner function) still holds a reference to it

counter(); // 1
counter(); // 2
counter(); // 3

function makeCounter() {
  let count = 0;
  return () => ++count;
}

const counterA = makeCounter();
const counterB = makeCounter(); // new call = new scope = independent count

counterA(); // 1
counterA(); // 2
counterA(); // 3
counterB(); // 1  ← independent from counterA
counterB(); // 2

function makeGreeter() {
  let name = 'Alice';

  const greet = () => console.log(`Hello, ${name}!`);
  const setName = (newName) => { name = newName; };

  return { greet, setName };
}

const greeter = makeGreeter();
greeter.greet();          // 'Hello, Alice!'
greeter.setName('Bob');   // updates the shared name
greeter.greet();          // 'Hello, Bob!' — closure sees the updated variable

// ❌ Classic bug with var
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// Prints: 3, 3, 3
// All three closures reference the same 'i' — which is 3 after the loop

// ✅ Fix with let — each iteration gets its own block-scoped 'i'
for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// Prints: 0, 1, 2
// Each closure captures its own separate 'i'

function Counter() {
  const [count, setCount] = useState(0);

  // handleClick is defined fresh on each render
  // It closes over the current 'count' value for that render
  function handleClick() {
    console.log(`Clicked! Current count is ${count}`);
    setCount(count + 1);
  }

  return <button onClick={handleClick}>{count}</button>;
}

// On the render where count === 2:
// handleClick closes over count = 2
// When clicked, it logs 'Current count is 2' and calls setCount(3)

function Counter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    // This effect runs once ([] dep array)
    // The closure captures count = 0 at mount time
    const interval = setInterval(() => {
      setCount(count + 1); // ❌ count is ALWAYS 0 here — stale closure!
    }, 1000);

    return () => clearInterval(interval);
  }, []); // empty deps — effect only runs on mount

  return <div>{count}</div>;
  // count stays 1 (0 + 1), never increments further
}

// ✅ Fix: use the functional updater form — no closure over count
useEffect(() => {
  const interval = setInterval(() => {
    setCount(prev => prev + 1); // gets fresh current value, not the stale closure
  }, 1000);

  return () => clearInterval(interval);
}, []);

function SearchBox({ onSearch }) {
  const [query, setQuery] = useState('');

  useEffect(() => {
    // This effect closes over 'query' and 'onSearch'
    // Adding them to the dependency array ensures the effect re-runs
    // with a fresh closure when they change
    const timer = setTimeout(() => {
      onSearch(query);
    }, 300);

    return () => clearTimeout(timer);
  }, [query, onSearch]); // ✅ fresh closure on each change

  return <input value={query} onChange={e => setQuery(e.target.value)} />;
}

function Parent() {
  const [count, setCount] = useState(0);

  // Without useCallback: handleClick is a new closure on every render
  // With useCallback: handleClick is only re-created when count changes
  const handleClick = useCallback(() => {
    console.log('count is', count);
    setCount(count + 1);
  }, [count]); // re-creates the closure when count changes

  return <Child onClick={handleClick} />;
}

// A factory that creates validators, each closing over its own rules
function createValidator(minLength, maxLength) {
  return function validate(value) {
    if (value.length < minLength) return `Minimum ${minLength} characters`;
    if (value.length > maxLength) return `Maximum ${maxLength} characters`;
    return null;
  };
}

const validateUsername = createValidator(3, 20);
const validateBio = createValidator(0, 500);

validateUsername('ab');       // 'Minimum 3 characters'
validateUsername('alice');    // null (valid)
validateBio('A long bio...'); // null (valid)

// Simple memoize: caches results by argument
function memoize(fn) {
  const cache = {}; // closure — persists across calls

  return function(arg) {
    if (cache[arg] !== undefined) {
      return cache[arg]; // return cached result
    }
    const result = fn(arg);
    cache[arg] = result;
    return result;
  };
}

const expensiveCalc = memoize(n => {
  console.log('calculating...');
  return n * n;
});

expensiveCalc(5); // logs 'calculating...' → 25
expensiveCalc(5); // returns 25 from cache — no log
expensiveCalc(6); // logs 'calculating...' → 36
